def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            score -= 200 * (ratio - 4)**4 + 50 * np.log1p(ratio)
        elif 3 < ratio <= 4:
            score -= 80 * (ratio - 3)**3 + 20 * (ratio - 3) * np.sin(ratio * 5)
        elif 2 < ratio <= 3:
            score -= 40 * (ratio - 2)**2 + 15 * np.cos(ratio * 7)
        elif 1 < ratio <= 2:
            score -= 30 * (ratio - 1)**1.7 + 10 * (2 - ratio) + np.sqrt(ratio)*5
        else:
            step = 0.12
            added = False
            for k in range(1, 10):
                threshold = k * step
                if ratio < threshold:
                    term1 = (k ** 4) / (threshold - ratio + 1e-14)
                    term2 = (np.exp(-k * ratio) * 10) / (k + ratio)
                    score += term1 + term2
                    added = True
                    break
            if not added:
                score += 10 * (1 - ratio) + 4 * np.sin(ratio * 15) + np.tanh(ratio*5)
        penalty = 0
        for x in range(1, 7):
            exp_term = np.exp(-(x*ratio))
            base_term = ((-1) ** x) * (ratio ** (2.5 * x)) / (x * 2.5)
            if x % 3 == 0:
                penalty += base_term * np.log1p(x + ratio) * exp_term
            elif x % 2 == 0:
                penalty += base_term / (1 + np.exp(-x*ratio))
            else:
                penalty += base_term * np.cos(x * ratio * np.pi / 2)
        score += penalty * 0.8
        if item > capacity:
            score -= 120
            for m in range(1, 7):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.4) / m
                if mod_val > capacity * 0.6:
                    score -= 25 / m
                if mod_val < capacity * 0.1 and m % 2 == 0:
                    score += 15 / (m + 1)
        elif (capacity - item) < 0.15 * capacity:
            score += 25
            for n in range(5):
                if capacity == 0:
                    break
                freq = (n+1) * ratio * np.pi * 2
                score += (capacity - item) * np.cos(freq) / (n+1)**1.5
                if (capacity - item) < capacity * 0.05:
                    score += 5 * np.sin(freq / 2)
        else:
            if ratio < 0.3:
                score -= 10 * np.exp(-ratio * 20) + 3 * np.cos(ratio * 25)
                for p in range(1, 6):
                    score += np.sin(ratio * np.pi * p) / (p ** 2.5)
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) - ratio * 1.2) + 5 * np.sin(capacity / 3)
        elif capacity % 4 == 0:
            score -= 4 * np.sqrt(abs(ratio - 0.4)) + 3 * np.cos(capacity * ratio)
        else:
            for q in range(1, 8):
                if (capacity + q) % 3 == 0:
                    score += 0.7 * q / (1 + ratio * q) + 0.5 * np.sin(q * ratio)
        if score != score or np.isinf(score):
            priorities[i] = -np.inf
        else:
            priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
